1	export function nextGeneration(cells: [number, number][]): [number, number][] {
2	  const isAlive = (x: number, y: number): boolean =>
3	    cells.some(([cx, cy]) => cx === x && cy === y);
4	
5	  const countNeighbors = (x: number, y: number): number => {
6	    let count = 0;
7	    for (let dx = -1; dx <= 1; dx++) {
8	      for (let dy = -1; dy <= 1; dy++) {
9	        if (dx === 0 && dy === 0) continue;
10	        if (isAlive(x + dx, y + dy)) count++;
11	      }
12	    }
13	    return count;
14	  };
15	
16	  return cells.filter(([x, y]) => {
17	    const neighbors = countNeighbors(x, y);
18	    return neighbors === 2 || neighbors === 3;
19	  });
20	}
